import React, { useState } from 'react';
import { useAuth } from '../../context/AuthContext';
import { useData } from '../../context/DataContext';

const MyTasks = () => {
  const { user } = useAuth();
  const { tasks, updateTaskProgress } = useData();
  const [tempReasons, setTempReasons] = useState({});

  // Lọc task của user
  const myRawTasks = tasks.filter(t => t.assigneeId === user.id);

  // Helper tính khoảng cách ngày
  const getDaysDiff = (targetDate) => {
    const now = new Date();
    const target = new Date(targetDate);
    const diffTime = target - now;
    return Math.ceil(diffTime / (1000 * 60 * 60 * 24)); 
  };

  // 1. Phân loại Task
  const categorizedTasks = {
    completed: myRawTasks.filter(t => t.progress === 100),
    upcoming: myRawTasks.filter(t => t.progress < 100 && new Date(t.startDate) > new Date()),
    inProgress: myRawTasks.filter(t => t.progress < 100 && new Date(t.startDate) <= new Date()),
  };

  // 2. Sắp xếp & Gắn nhãn cho In Progress (Ưu tiên deadline gần nhất)
  const sortedInProgress = categorizedTasks.inProgress.sort((a, b) => new Date(a.deadline) - new Date(b.deadline));

  const handleConfirmUpdate = (taskId, currentProgress) => {
    const reason = tempReasons[taskId] || '';
    if (currentProgress < 90 && !reason.trim()) {
      alert("Thông báo: Bạn bắt buộc phải nhập lý do giải thích khi mức độ hoàn thành dưới 90%!");
      return;
    }
    updateTaskProgress(taskId, currentProgress, reason);
    alert("Cập nhật tiến độ thành công!");
  };

  const renderTaskCard = (task) => {
    const daysLeft = getDaysDiff(task.deadline);
    const isUrgent = daysLeft <= 2 && daysLeft >= 0; // Gấp nếu còn <= 2 ngày

    return (
      <div key={task.id} style={{ border: '1px solid #ccc', padding: '15px', borderRadius: '8px', background: isUrgent ? '#fff1f0' : 'white', marginBottom: '15px', position: 'relative' }}>
        {isUrgent && (
          <span style={{ position: 'absolute', top: -10, right: 10, background: 'red', color: 'white', padding: '2px 8px', borderRadius: '10px', fontSize: '0.8rem', fontWeight: 'bold' }}>
            CẦN HOÀN THÀNH GẤP
          </span>
        )}
        <h4>{task.title}</h4>
        <p style={{fontSize: '0.9rem', color: '#666'}}>
          Thời gian: {task.startDate} đến <strong>{task.deadline}</strong> ({daysLeft < 0 ? 'Đã quá hạn' : `Còn ${daysLeft} ngày`})
        </p>
        
        <label>Tiến độ: <strong>{task.progress}%</strong></label>
        <input 
          type="range" min="0" max="100" value={task.progress} 
          onChange={(e) => updateTaskProgress(task.id, parseInt(e.target.value), task.reason)}
          style={{ width: '100%', marginTop: '10px' }}
          disabled={task.progress === 100} // Khóa nếu đã xong (logic tùy chọn)
        />

        {task.progress < 90 && task.progress !== 100 && (
          <div style={{ marginTop: '10px' }}>
             <textarea
              placeholder="Nhập lý do nếu < 90%..."
              value={tempReasons[task.id] !== undefined ? tempReasons[task.id] : task.reason}
              onChange={(e) => setTempReasons({ ...tempReasons, [task.id]: e.target.value })}
              style={{ width: '100%', height: '50px', padding: '5px' }}
            />
          </div>
        )}
        
        <button 
          onClick={() => handleConfirmUpdate(task.id, task.progress)}
          style={{ marginTop: '10px', padding: '5px 15px', background: '#1890ff', color: 'white', border: 'none', borderRadius: '4px', cursor: 'pointer' }}
        >
          Cập nhật
        </button>
      </div>
    );
  };

  return (
    <div>
      <h2>Công việc của tôi</h2>
      
      {/* 2. Mảng tổng hợp Task Performance */}
      <div style={{ display: 'flex', gap: '15px', marginBottom: '30px' }}>
        <div style={{ flex: 1, background: '#e6f7ff', padding: '15px', borderRadius: '8px', textAlign: 'center' }}>
          <h3 style={{margin: 0, color: '#1890ff'}}>{categorizedTasks.completed.length}</h3>
          <span>Đã hoàn thành</span>
        </div>
        <div style={{ flex: 1, background: '#fff7e6', padding: '15px', borderRadius: '8px', textAlign: 'center' }}>
          <h3 style={{margin: 0, color: '#fa8c16'}}>{categorizedTasks.inProgress.length}</h3>
          <span>Đang diễn ra</span>
        </div>
        <div style={{ flex: 1, background: '#f6ffed', padding: '15px', borderRadius: '8px', textAlign: 'center' }}>
          <h3 style={{margin: 0, color: '#52c41a'}}>{categorizedTasks.upcoming.length}</h3>
          <span>Sắp tới</span>
        </div>
      </div>

      <h3 style={{ borderBottom: '2px solid #1890ff', paddingBottom: '5px', display: 'inline-block' }}>Đang thực hiện (Ưu tiên)</h3>
      <div>{sortedInProgress.length > 0 ? sortedInProgress.map(renderTaskCard) : <p>Không có task đang diễn ra.</p>}</div>

      <h3 style={{ borderBottom: '2px solid #52c41a', paddingBottom: '5px', display: 'inline-block', marginTop: '30px' }}>Sắp tới</h3>
      <div style={{ opacity: 0.7 }}>
        {categorizedTasks.upcoming.map(t => (
           <div key={t.id} style={{ border: '1px dashed #ccc', padding: '10px', marginBottom: '10px' }}>
             <strong>{t.title}</strong> - Bắt đầu: {t.startDate}
           </div>
        ))}
      </div>

      <h3 style={{ borderBottom: '2px solid #888', paddingBottom: '5px', display: 'inline-block', marginTop: '30px' }}>Đã hoàn thành</h3>
      <div>
        {categorizedTasks.completed.map(t => (
           <div key={t.id} style={{ background: '#f0f0f0', padding: '10px', marginBottom: '10px', textDecoration: 'line-through', color: '#888' }}>
             {t.title} (Xong ngày: {t.completedDate})
           </div>
        ))}
      </div>
    </div>
  );
};

export default MyTasks;
